// CustomerRequest.java - DTO de entrada
package com.paymentchange.customer.dto.request;

import io.swagger.v3.oas.annotations.media.Schema;
import lombok.Data;
import java.util.List;

@Data
@Schema(description = "Modelo de petición para crear/actualizar cliente")
public class CustomerRequest {

    @Schema(
        description = "Nombre completo del cliente",
        example = "María González",
        required = true
    )
    private String name;

    @Schema(
        description = "Número de teléfono",
        example = "+52-555-9876-5432"
    )
    private String phoneNumber;

    @Schema(
        description = "Correo electrónico",
        example = "maria.gonzalez@email.com"
    )
    private String email;

    @Schema(
        description = "IDs de productos a asociar",
        example = "[1, 2]"
    )
    private List<Long> productIds;

    // Sin ID, sin timestamps, sin campos internos
}

// CustomerResponse.java - DTO de salida
package com.paymentchange.customer.dto.response;

import io.swagger.v3.oas.annotations.media.Schema;
import lombok.Data;
import java.util.List;

@Data
@Schema(description = "Modelo de respuesta con datos del cliente")
public class CustomerResponse {

    @Schema(description = "ID del cliente", example = "1")
    private Long id;

    @Schema(description = "Nombre del cliente", example = "María González")
    private String name;

    @Schema(description = "Teléfono", example = "+52-555-9876-5432")
    private String phoneNumber;

    @Schema(description = "Email", example = "maria.gonzalez@email.com")
    private String email;

    @Schema(description = "Estado del cliente", example = "ACTIVE")
    private String status;

    @Schema(description = "IDs de productos asociados", example = "[1, 2]")
    private List<Long> productIds;

    // Incluye ID para referencia
    // NO incluye: createdAt, updatedAt, versión, etc.
}

// Entidad Customer original (NO exponer directamente)
@Data
@Entity
public class Customer {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    private String name;
    private String phoneNumber;
    private String email;
    private String status;

    @ElementCollection
    private List<Long> productIds;

    // Campos internos NO expuestos en API
    private LocalDateTime createdAt;
    private LocalDateTime updatedAt;
    private Integer version;
    private String internalNotes;  // Campo interno
}
